const { OpenAI } = require('langchain/llms/openai');
const llm = new OpenAI({ temperature: 0.9 });
const text = 'Translate this into French.';
llm.call(text).then(console.log);

const { PromptTemplate } = require('langchain/prompts');
const template = new PromptTemplate({ inputVariables: ['name'], template: 'Who is {name}?' });
console.log(template.format({ name: 'Nikola Tesla' }));

const { LLMChain } = require('langchain/chains');
const chain = new LLMChain({ llm, prompt: template });
chain.run('Galileo').then(console.log);
